import HomeBanner from "../../Components/Header/HomeBanner";

const Home = () => {
  return (
    <>
      <HomeBanner />
      <section className="homeProducts">
        <div className="container">
          <div className="row">
            <div className="col-md-3">
              <div className="banner">
                <img
                  src="https://product.hstatic.net/200000642007/product/50ivs_3apqb0243_1_d96aec8dc0334147b80dc8dd727effd4_859994829c1445e08289843a637f13a7_master.jpg"
                  className="cursor"
                />
              </div>
            </div>
            <div className="col-md-3">
              <div className="d-flex"></div>
            </div>
          </div>
        </div>
      </section>
    </>
  );
};
export default Home;
